  5023→  if (StaticPrefs::network_fetch_cache_partition_cross_origin() &&
  5024→      (NS_FAILED(mLoadInfo->TriggeringPrincipal()->IsThirdPartyChannel(
  5025→           this, &isThirdParty)) ||
