  5040→
  5041→  // If the browser is set to offline, or it doesn't have any active network
  5042→  // interfaces then don't race, as it's unlikely the network would win :)
  5043→  if (NS_IsOffline()) {
  5044→    maybeRCWN = false;
  5045→  }
  5046→
  5047→  if ((mNetworkTriggerDelay || RCWNEnabled()) && maybeRCWN && mAllowRCWN) {
  5048→    bool hasAltData = false;
  5049→    uint32_t sizeInKb = 0;
  5050→    rv = cacheStorage->GetCacheIndexEntryAttrs(
  5051→        mCacheEntryURI, mCacheIdExtension, &hasAltData, &sizeInKb);
  5052→
  5053→    // We will attempt to race the network vs the cache if we've found
